\begin{aligned}
&N = 2^{y - x} \\
&x \text{ — номер исходного формата} \\
&y \text{ — номер нужного формата} \\
&N \text{ — количество листов формата } A_y \text{ из одного листа формата } A_x
\end{aligned}

\begin{aligned}
&S_1 \cdot \frac{x}{100} = S_2 \cdot \frac{x}{100} + S_3 \cdot \frac{y}{100} \\
&S_1 \text{ — длина маршрута полностью по шоссе (в км)} \\
&S_2 \text{ — длина участка по шоссе в альтернативном пути (в км)} \\
&S_3 \text{ — длина участка по просёлочной дороге в альтернативном пути (в км)} \\
&x \text{ — расход топлива по шоссе (л на 100 км)} \\
&y \text{ — расход топлива по просёлочной дороге (л на 100 км)}
\end{aligned}
